(538, 'Cho thuê tòa nhà tại Thái Nguyên - 402m2 - Nghiên Loan', 'Tòa nhà cho thuê tại Thái Nguyên, vị trí thuận tiện di chuyển.\nDiện tích sử dụng 402m2, phù hợp làm văn phòng hoặc kinh doanh.\nƯu tiên khách thuê dài hạn, hỗ trợ xem nhà linh hoạt.', 'Nhà trọ', 6, 'Tây Bắc', 'rent', 0, 6, 0, 0, 2, '1', 402, '27', 'Xã Nghiên Loan, Thái Nguyên', 86, 10595, 'zillhms2.jpg', 'zillhms6.jpg', 'zillhms1.jpg', 'zillhms4.jpg', 'zillhms3.jpg', 43, 'available', 'approved', 1, NULL, '1777904006_mapimage_floorplan_sample.jpg', '1777904006_mapimage_floorplan_sample.jpg', 'floorplan_sample.jpg', '7', '2026-05-10 19:51:18', 0, 1),
(539, 'Cho thuê căn hộ tại Cao Bằng - 2PN - 78m2 - Hà Quảng', 'Căn hộ Cao Bằng giá tốt, khu vực Hà Quảng.\nThiết kế 2 phòng ngủ, 2 phòng tắm, đầy đủ bếp và phòng khách.\nƯu tiên khách thuê dài hạn, hỗ trợ xem nhà linh hoạt.', 'Căn hộ chung cư', 1, 'Nam', 'rent', 2, 2, 1, 1, 1, '18', 78, '26', 'Xã Hà Quảng, Cao Bằng', 80, 10175, 'zillhms2.jpg', 'zillhms6.jpg', 'zillhms1.jpg', 'zillhms4.jpg', 'zillhms3.jpg', 58, 'available', 'approved', 1, NULL, '1777904006_mapimage_floorplan_sample.jpg', '1777904006_mapimage_floorplan_sample.jpg', 'floorplan_sample.jpg', '42', '2026-05-10 19:51:18', 0, 0),
