(634, 'Cho thuê văn phòng tại Hưng Yên - 201m2 - Hồng Quang', 'Không gian văn phòng tại Hưng Yên phù hợp cho startup/doanh nghiệp.\nDiện tích 201m2, dễ bố trí khu làm việc và tiếp khách.\nƯu tiên khách thuê dài hạn, hỗ trợ xem nhà linh hoạt.', 'Văn phòng', 7, 'Tây Bắc', 'rent', 0, 1, 0, 0, 2, '13', 201, '22', 'Xã Hồng Quang, Hưng Yên', 92, 11182, 'zillhms2.jpg', 'zillhms6.jpg', 'zillhms1.jpg', 'zillhms4.jpg', 'zillhms3.jpg', 43, 'available', 'approved', 1, NULL, '1777904006_mapimage_floorplan_sample.jpg', '1777904006_mapimage_floorplan_sample.jpg', 'floorplan_sample.jpg', '24', '2026-05-10 19:51:19', 0, 0),
(635, 'Cho thuê căn hộ tại Khánh Hòa - 3PN - 90m2 - Cà Ná', 'Căn hộ Khánh Hòa giá tốt, khu vực Cà Ná.\nThiết kế 3 phòng ngủ, 2 phòng tắm, đầy đủ bếp và phòng khách.\nƯu tiên khách thuê dài hạn, hỗ trợ xem nhà linh hoạt.', 'Căn hộ chung cư', 1, 'Tây Nam', 'rent', 3, 2, 0, 1, 1, '2', 90, '85', 'Xã Cà Ná, Khánh Hòa', 102, 12263, 'zillhms2.jpg', 'zillhms6.jpg', 'zillhms1.jpg', 'zillhms4.jpg', 'zillhms3.jpg', 45, 'available', 'approved', 1, NULL, '1777904006_mapimage_floorplan_sample.jpg', '1777904006_mapimage_floorplan_sample.jpg', 'floorplan_sample.jpg', '44', '2026-05-10 19:51:19', 0, 0),
(636, 'Cho thuê căn hộ tại Hà Nội - 3PN - 91m2 - Kim Liên', 'Căn hộ Hà Nội giá tốt, khu vực Kim Liên.\nThiết kế 3 phòng ngủ, 2 phòng tắm, đầy đủ bếp và phòng khách.\nƯu tiên khách thuê dài hạn, hỗ trợ xem nhà linh hoạt.', 'Căn hộ chung cư', 1, 'Tây Bắc', 'rent', 3, 2, 1, 1, 1, '5', 91, '26', 'Phường Kim Liên, Hà Nội', 79, 10045, 'zillhms2.jpg', 'zillhms6.jpg', 'zillhms1.jpg', 'zillhms4.jpg', 'zillhms3.jpg', 58, 'available', 'approved', 1, NULL, '1777904006_mapimage_floorplan_sample.jpg', '1777904006_mapimage_floorplan_sample.jpg', 'floorplan_sample.jpg', '22', '2026-05-10 19:51:19', 0, 2),
(637, 'Cho thuê tòa nhà tại Vĩnh Long - 586m2 - Tân Long Hội', 'Tòa nhà cho thuê tại Vĩnh Long, vị trí thuận tiện di chuyển.\nDiện tích sử dụng 586m2, phù hợp làm văn phòng hoặc kinh doanh.\nƯu tiên khách thuê dài hạn, hỗ trợ xem nhà linh hoạt.', 'Nhà trọ', 6, 'Đông Bắc', 'rent', 0, 4, 0, 0, 1, '1', 586, '2', 'Xã Tân Long Hội, Vĩnh Long', 109, 13047, 'zillhms2.jpg', 'zillhms6.jpg', 'zillhms1.jpg', 'zillhms4.jpg', 'zillhms3.jpg', 49, 'available', 'approved', 1, NULL, '1777904006_mapimage_floorplan_sample.jpg', '1777904006_mapimage_floorplan_sample.jpg', 'floorplan_sample.jpg', '18', '2026-05-10 19:51:19', 0, 0);
